create table images
(
    id         bigint unsigned auto_increment
        primary key,
    created_at datetime(3)      null,
    updated_at datetime(3)      null,
    deleted_at datetime(3)      null,
    name       varchar(191)     null comment '镜像名称',
    type       bigint default 1 null comment '镜像类型:1系统镜像2自定义镜像',
    user_id    bigint           null comment '用户ID',
    image_path varchar(191)     null comment '镜像路径',
    harbor_id  bigint           null comment 'Harbor ID',
    image_addr varchar(191)     null comment '镜像地址',
    size       varchar(191)     null comment '镜像大小',
    image_uuid varchar(191)     null comment '镜像UUID',
    area       varchar(191)     null comment '镜像区域',
    usage_type bigint           null comment '镜像用途:1容器实例2训练镜像3推理镜像'
);

create index idx_images_deleted_at
    on images (deleted_at);

